@app.route('/api/auth/verify', methods=['POST'])
def verify_and_authenticate():
    """Verify signature and create authenticated session"""
    try:
        data = request.get_json()
        
        # Validate required fields
        required_fields = ['address', 'signature', 'message']
        if not data or not all(field in data for field in required_fields):
            return jsonify({'error': 'Missing required fields'}), 400
        
        address = data['address']
        signature = data['signature']
        message = data['message']
        
        # Validate address
        if not validate_ethereum_address(address):
            return jsonify({'error': 'Invalid Ethereum address'}), 400
        
        # Normalize address
        address = normalize_address(address)
        
        # Clean up expired nonces
        cleanup_expired_nonces()
        
        # Check if nonce exists for this address
        if address not in nonces:
            return jsonify({'error': 'No nonce found for this address. Request a nonce first.'}), 400
        
        nonce_data = nonces[address]
        expected_nonce = nonce_data['nonce']
        
        # Verify the message contains the correct nonce
        if expected_nonce not in message:
            return jsonify({'error': 'Invalid message or nonce'}), 400
        
        # Verify signature
        if not verify_signature(message, signature, address):
            return jsonify({'error': 'Invalid signature'}), 401
        
        # Delete used nonce
        del nonces[address]
        
        # Create session
        session_token = generate_session_token()
        expires_at = datetime.utcnow() + timedelta(hours=SESSION_EXPIRY_HOURS)
        
        sessions[session_token] = {
            'address': address,
            'created_at': datetime.utcnow(),
            'expires_at': expires_at
        }
        
        return jsonify({
            'success': True,
            'token': session_token,
            'address': address,
            'expires_at': expires_at.isoformat()
        }), 200
        
    except Exception as e:
        return jsonify({'error': 'Internal server error'}), 500


